     3→import { Layout } from "./Layout";
     4→import { BreadcrumbProvider } from "./BreadcrumbContext";
     5→import { ActiveSessions } from "./screens/ActiveSessions";
     6→import { SessionTree } from "./screens/SessionTree";
     7→import { SessionDetail } from "./screens/SessionDetail";
     8→import { Checkpoints } from "./screens/Checkpoints";
     9→import { CheckpointTimeline } from "./screens/CheckpointTimeline";
    10→import { CheckpointDetail } from "./screens/CheckpointDetail";
    11→import { Search } from "./screens/Search";
    12→import { Repos } from "./screens/Repos";
    13→import { BranchLog } from "./screens/BranchLog";
    14→
    15→export default function App() {
    16→  return (
    17→    <BreadcrumbProvider>
    18→    <MemoryRouter>
    19→      <Routes>
    20→        <Route path="/" element={<Layout />}>
    21→          <Route index element={<ActiveSessions />} />
    22→          <Route path="session-tree" element={<SessionTree />} />
    23→          <Route path="sessions/:sessionId" element={<SessionDetail />} />
    24→          <Route path="checkpoints" element={<Checkpoints />} />
    25→          <Route path="checkpoints/timeline" element={<CheckpointTimeline />} />
    26→          <Route path="checkpoints/:checkpointId" element={<CheckpointDetail />} />
    27→          <Route path="search" element={<Search />} />
    28→          <Route path="repos" element={<Repos />} />
    29→          <Route path="branch-log" element={<BranchLog />} />
    30→        </Route>
    31→      </Routes>
    32→    </MemoryRouter>
    33→    </BreadcrumbProvider>
    34→  );
