    66→export async function fetchRepoStatuses(): Promise<RepoStatus[]> {
    67→  const res = await fetch(`${API_BASE}/repos/status`);
    68→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    69→  return res.json() as Promise<RepoStatus[]>;
    70→}
