    90→export async function addRepo(repo: { name: string; remote: string; localPath: string }): Promise<RepoConfig> {
    91→  const res = await fetch(`${API_BASE}/repos`, {
    92→    method: "POST",
    93→    headers: { "Content-Type": "application/json" },
    94→    body: JSON.stringify(repo),
    95→  });
    96→  if (!res.ok) throw new Error(`HTTP ${res.status}`);
    97→  return res.json() as Promise<RepoConfig>;
    98→}
