   351→  id: number,
   352→  status: "open" | "in_progress" | "complete" | "na",
   353→  subSessionId?: string,
   354→): Promise<void> {
   355→  const res = await fetch(`${API_BASE}/open-items/${id}`, {
   356→    method: "PATCH",
   357→    headers: { "Content-Type": "application/json" },
