import React, { useEffect, useRef } from "react";
import { Terminal as XTerm } from "@xterm/xterm";
import { FitAddon } from "@xterm/addon-fit";
import "@xterm/xterm/css/xterm.css";

declare global {
  interface Window {
    pty: {
      spawn: () => Promise<void>;
      write: (data: string) => void;
      resize: (cols: number, rows: number) => void;
      kill: () => void;
      onData: (cb: (data: string) => void) => void;
      onExit: (cb: () => void) => void;
      removeAllListeners: () => void;
    };
  }
}

interface TerminalProps {
  active: boolean;
}

export function Terminal({ active }: TerminalProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const fitAddonRef = useRef<FitAddon | null>(null);
  const initializedRef = useRef(false);

  // Initialize only on first activation (when the container is actually visible)
  useEffect(() => {
    if (!active || initializedRef.current || !containerRef.current) return;
    initializedRef.current = true;

    const term = new XTerm({
      fontFamily: '"Menlo", "Monaco", "Courier New", monospace',
      fontSize: 13,
      lineHeight: 1.2,
      cursorBlink: true,
      theme: {
        background: "#1a1b1e",
        foreground: "#c1c2c5",
        cursor: "#c1c2c5",
        black: "#1a1b1e",
        red: "#fa5252",
        green: "#40c057",
        yellow: "#fab005",
        blue: "#4dabf7",
        magenta: "#cc5de8",
        cyan: "#22b8cf",
        white: "#c1c2c5",
        brightBlack: "#5c5f66",
        brightRed: "#ff6b6b",
        brightGreen: "#69db7c",
        brightYellow: "#ffd43b",
        brightBlue: "#74c0fc",
        brightMagenta: "#da77f2",
        brightCyan: "#3bc9db",
        brightWhite: "#ffffff",
      },
    });

    const fitAddon = new FitAddon();
    fitAddonRef.current = fitAddon;
    term.loadAddon(fitAddon);
    term.open(containerRef.current);
    fitAddon.fit();

    window.pty.spawn().then(() => {
      window.pty.resize(term.cols, term.rows);
    });

    window.pty.onData((data) => term.write(data));
    window.pty.onExit(() => term.write("\r\n\x1b[2m[process exited]\x1b[0m\r\n"));
    term.onData((data) => window.pty.write(data));

    const observer = new ResizeObserver(() => {
      try {
        fitAddon.fit();
        window.pty.resize(term.cols, term.rows);
      } catch {}
    });
    observer.observe(containerRef.current);

    return () => {
      observer.disconnect();
      window.pty.removeAllListeners();
      window.pty.kill();
      fitAddonRef.current = null;
      term.dispose();
    };
  }, [active]);

  // Re-fit when navigating back to the terminal
  useEffect(() => {
    if (active && initializedRef.current && fitAddonRef.current) {
      requestAnimationFrame(() => {
        try { fitAddonRef.current?.fit(); } catch {}
      });
    }
  }, [active]);

  return (
    <div
      ref={containerRef}
      style={{
        width: "100%",
        height: "100%",
        backgroundColor: "#1a1b1e",
        padding: 8,
        boxSizing: "border-box",
      }}
    />
  );
}

