import { app, BrowserWindow, ipcMain } from "electron";
import { join } from "path";
import { spawn } from "child_process";
import * as pty from "node-pty";
import os from "os";

let mainWindow: BrowserWindow | null = null;
let ptyProcess: pty.IPty | null = null;

function setupPtyIpc(): void {
  ipcMain.handle("pty:spawn", () => {
    if (ptyProcess) {
      ptyProcess.kill();
      ptyProcess = null;
    }
    const shell = process.env.SHELL || (process.platform === "win32" ? "cmd.exe" : "bash");
    ptyProcess = pty.spawn(shell, [], {
      name: "xterm-256color",
      cols: 80,
      rows: 24,
      cwd: os.homedir(),
      env: process.env as Record<string, string>,
    });
    ptyProcess.onData((data) => {
      mainWindow?.webContents.send("pty:data", data);
    });
    ptyProcess.onExit(() => {
      mainWindow?.webContents.send("pty:exit");
      ptyProcess = null;
    });
  });

  ipcMain.on("pty:write", (_e, data: string) => {
    ptyProcess?.write(data);
  });

  ipcMain.on("pty:resize", (_e, cols: number, rows: number) => {
    try { ptyProcess?.resize(cols, rows); } catch {}
  });

  ipcMain.on("pty:kill", () => {
    ptyProcess?.kill();
    ptyProcess = null;
  });
}

function createWindow(): void {
  mainWindow = new BrowserWindow({
    width: 1400,
    height: 900,
    webPreferences: {
      preload: join(__dirname, "../preload/index.js"),
      contextIsolation: true,
      nodeIntegration: false,
    },
  });

  if (process.env.ELECTRON_RENDERER_URL) {
    mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL);
    mainWindow.webContents.openDevTools();
  } else {
    mainWindow.loadFile(join(__dirname, "../renderer/index.html"));
  }
}

app.whenReady().then(() => {
  setupPtyIpc();
  createWindow();
});

app.on("window-all-closed", () => {
  if (process.platform !== "darwin") app.quit();
});

app.on("activate", () => {
  if (BrowserWindow.getAllWindows().length === 0) createWindow();
});

