          onNewTab={handleNewTab}
        />
        <Box style={{ flex: 1, overflow: "hidden", display: isTerminal ? "none" : "flex", flexDirection: "column" }}>
          <Outlet />
        </Box>
      </AppShell.Main>
    </AppShell>
  </TerminalContext.Provider>
  );
}

content.text:
Clean. Here's what you now have:

**Multiple terminals, all kept alive:**
- Each tab has its own PTY process in the main process (keyed by id)
- All terminal panels are always mounted — switching tabs is instant, no session loss

**Opening terminals from anywhere in the app:**
```tsx
import { useTerminal } from "../TerminalContext";

function SomeScreen() {
  const { openTerminal } = useTerminal();

  // Open a plain terminal
  openTerminal();

  // Open one in a specific directory (e.g. from a repo or checkpoint)
  openTerminal({ cwd: "/path/to/repo", label: "fix: auth bug" });

  // Open or focus a named terminal (e.g. one per session)
  openTerminal({ id: sessionId, label: session.name, cwd: session.localPath });
}
```

The `id` deduplication means calling `openTerminal({ id: sessionId })` will focus the existing tab rather than opening a duplicate — perfect for "one terminal per Claude session."
